func (c *Connector) NewReadMethod(ctx context.Context, params streaming.NewParams) ([]SomeResult, error) {
    return withRetry(ctx, c, func() ([]SomeResult, error) {
        return c.downstreamConnector.NewReadMethod(ctx, params)
    })
}
